const items = $input.all();
const today = new Date();

function parseDocDate(str) {
  const months = { Jan:0, Feb:1, Mar:2, Apr:3, May:4, Jun:5, Jul:6, Aug:7, Sep:8, Oct:9, Nov:10, Dec:11 };
  const m = str.match(/(\d{2})([A-Za-z]{3})(\d{4})/);
  if (!m) return null;
  return new Date(parseInt(m[3]), months[m[2]], parseInt(m[1]));
}

function safeMd(str) {
  if (!str) return '';
  return str.replace(/_/g, ' ');
}

const current = items.filter(item => {
  const d = parseDocDate(item.json.doc_date || '');
  if (!d) return false;
  return Math.floor((today - d) / 86400000) <= 30;
});

if (current.length === 0) {
  return [{ json: { result: "No current signals in the last 30 days." } }];
}

// Deduplicate by stock_name — keep most recent
const deduped = {};
current.forEach(item => {
  const name = item.json.stock_name;
  const d = parseDocDate(item.json.doc_date || '');
  const existing = deduped[name] ? parseDocDate(deduped[name].json.doc_date) : null;
  if (!existing || d > existing) deduped[name] = item;
});

const sectorStances = ['positive', 'cautious', 'negative'];
const stanceEmoji = {
  buy: '🟢', sell: '🔴', trim: '🟡', add: '🟢',
  avoid: '🔴', conviction_change: '🔵', hold: '⚪'
};

const getBucket = (stance) => {
  if (['sell', 'avoid', 'negative'].includes(stance)) return 'act_now';
  if (['buy', 'add', 'positive'].includes(stance)) return 'opportunity';
  return 'watch';
};

const buckets = { act_now: [], opportunity: [], watch: [] };

Object.values(deduped).forEach(item => {
  const stance = item.json.stance || 'unknown';
  const isSector = sectorStances.includes(stance);
  const emoji = isSector ? '🏦' : (stanceEmoji[stance] || '⚪');
  const bucket = getBucket(stance);
  buckets[bucket].push({
    label: `${emoji} ${item.json.stock_name} — ${stance} (${safeMd(item.json.channel)}, ${item.json.doc_date})`,
    doc_date: item.json.doc_date
  });
});

const MAX = 10;
let hasMore = false;
const lines = ['SignalDesk — Last 30 Days', ''];

const printBucket = (key, header) => {
  if (buckets[key].length === 0) return;
  buckets[key].sort((a, b) => (parseDocDate(b.doc_date) || 0) - (parseDocDate(a.doc_date) || 0));
  lines.push(header);
  const total = buckets[key].length;
  buckets[key].slice(0, MAX).forEach(s => lines.push(`  ${s.label}`));
  if (total > MAX) { hasMore = true; lines.push(`  ...and ${total - MAX} more`); }
  lines.push('');
};

printBucket('act_now', '⚡ Act now');
printBucket('opportunity', '📈 Opportunity');
printBucket('watch', '👀 Watch');

if (hasMore) {
  lines.push('Capped at 10 per section. Ask me about a specific stock or sector for more.');
}

return [{ json: { result: lines.join('\n') } }];
